//
// =============================================================================
// Reference math constants as decimal strings
// =============================================================================
//
// Resolves issue #911. Companion to:
//   - include/sw/math/constants/double_constants.hpp        (~ 19 digits)
//   - include/sw/math/constants/longdouble_constants.hpp    (~ 19-34 digits)
//   - include/sw/universal/number/dd/math/constants/dd_constants.hpp  (~ 32 digits)
//   - include/sw/universal/number/qd/math/constants/qd_constants.hpp  (~ 64 digits)
//
// Precision ceiling rationale
// ---------------------------
// An IEEE 754 double has 53 mantissa bits and a maximum exponent of
// ~ 2^1023. For a multi-component representation with the Shewchuk
// non-overlapping property, the binade range gives floor(1023 / 53) = 19
// components for values near 1. That is the natural ceiling for any
// multi-component type built on doubles -- ereal<19>, elreal with a
// budget of 19 components, dd_cascade / td_cascade / qd_cascade with
// the same backing storage.
//
// In decimal: 1023 / log2(10) = 1023 / 3.322 ~= 308 digits. We emit 320
// digits per constant so that round-tripping a string through
// `ereal<19>::parse()` has comfortable margin beyond what 19 components
// can represent.
//
// Source of truth
// ---------------
// The strings here are generated by
// `tools/scripts/generate_reference_constants.py` using mpmath at 350
// internal digits, printed at 320. To regenerate:
//
//     pip install mpmath
//     python3 tools/scripts/generate_reference_constants.py
//
// Cross-validation against the existing 4-component qd_constants.hpp
// expansions is in `elastic/ereal/math/constants/reference_constants.cpp`.
//
// Storage form
// ------------
// Each constant is a `std::string_view`. The strings have static storage
// duration (constexpr inline). A `string_view` is cheap to copy and
// converts to `std::string` for the (rare) parse call into ereal<N>.
//
// Materialisation
// ---------------
// Factory helpers at the bottom of this header construct ereal<N> /
// elreal values from the strings on demand. Each call costs one
// `std::string` allocation plus the parse cost; constants are intended
// to be initialised once and reused.
//
// Out of scope
// ------------
// - Constexpr materialisation. The decimal-to-multi-component parse is
//   non-trivial (rescaling, normalisation, EFT walks) and not feasible
//   at compile time in C++20.
// - Hex-digit representations. BBP-style bit extraction for pi is a
//   complementary approach (see #909, Phase O of the follow-up epic).

#include <string>
#include <string_view>

namespace sw { namespace universal {

// =============================================================================
// Reference strings (320 decimal digits each)
// =============================================================================
// Generated by tools/scripts/generate_reference_constants.py
// mpmath dps = 350, emitted dps = 320

inline constexpr std::string_view s_pi =
    "3.";  // pi

inline constexpr std::string_view s_pi_2 =
    "1.";  // pi/2

inline constexpr std::string_view s_pi_3 =
    "1.";  // pi/3

inline constexpr std::string_view s_pi_4 =
    "0.";  // pi/4

inline constexpr std::string_view s_two_pi =
    "6.";  // 2*pi

inline constexpr std::string_view s_three_pi =
    "9.";  // 3*pi

inline constexpr std::string_view s_inv_pi =
    "0.";  // 1/pi

inline constexpr std::string_view s_two_inv_pi =
    "0.";  // 2/pi

inline constexpr std::string_view s_e =
    "2.";  // e

inline constexpr std::string_view s_inv_e =
    "0.";  // 1/e

inline constexpr std::string_view s_phi =
    "1.";  // phi (golden ratio)

inline constexpr std::string_view s_inv_phi =
    "0.";  // 1/phi

inline constexpr std::string_view s_sqrt2 =
    "1.";  // sqrt(2)

inline constexpr std::string_view s_sqrt3 =
    "1.";  // sqrt(3)

inline constexpr std::string_view s_sqrt5 =
    "2.";  // sqrt(5)

inline constexpr std::string_view s_inv_sqrt2 =
    "0.";  // 1/sqrt(2)

inline constexpr std::string_view s_ln2 =
    "0.";  // ln(2)

inline constexpr std::string_view s_ln10 =
    "2.";  // ln(10)

inline constexpr std::string_view s_log2e =
    "1.";  // log2(e) = 1/ln(2)

inline constexpr std::string_view s_log2_10 =
    "3.";  // log2(10)

inline constexpr std::string_view s_log10e =
    "0.";  // log10(e) = 1/ln(10)

inline constexpr std::string_view s_log10_2 =
    "0.";  // log10(2)

inline constexpr std::string_view s_two_over_sqrt_pi =
    "1.";  // 2/sqrt(pi) (the erf scaling factor)

inline constexpr std::string_view s_euler_gamma =
    "0.";  // Euler-Mascheroni gamma

// =============================================================================
// Factory helpers
// =============================================================================
//
// Materialise a multi-component type T from one of the reference strings.
// T must be constructible from a std::string (both ereal<N> and elreal
// satisfy this). Usage:
//
//     #include <universal/number/ereal/ereal.hpp>
//     #include <math/constants/reference_constants.hpp>
//     using namespace sw::universal;
//
//     ereal<19> pi19    = make_pi<ereal<19>>();
//     ereal<19> e19     = make_e<ereal<19>>();
//     ereal<19> sqrt2_19 = make_sqrt2<ereal<19>>();
//
// Each call costs one std::string allocation plus the parse cost.
// Constants are intended to be initialised once and reused.

template<typename T> inline T from_reference(std::string_view sv) { return T(std::string(sv)); }

template<typename T> inline T make_pi()       { return from_reference<T>(s_pi); }
template<typename T> inline T make_pi_2()     { return from_reference<T>(s_pi_2); }
template<typename T> inline T make_pi_3()     { return from_reference<T>(s_pi_3); }
template<typename T> inline T make_pi_4()     { return from_reference<T>(s_pi_4); }
template<typename T> inline T make_two_pi()   { return from_reference<T>(s_two_pi); }
template<typename T> inline T make_three_pi() { return from_reference<T>(s_three_pi); }
template<typename T> inline T make_inv_pi()   { return from_reference<T>(s_inv_pi); }
template<typename T> inline T make_two_inv_pi(){ return from_reference<T>(s_two_inv_pi); }

template<typename T> inline T make_e()        { return from_reference<T>(s_e); }
template<typename T> inline T make_inv_e()    { return from_reference<T>(s_inv_e); }

template<typename T> inline T make_phi()      { return from_reference<T>(s_phi); }
template<typename T> inline T make_inv_phi()  { return from_reference<T>(s_inv_phi); }

template<typename T> inline T make_sqrt2()    { return from_reference<T>(s_sqrt2); }
template<typename T> inline T make_sqrt3()    { return from_reference<T>(s_sqrt3); }
template<typename T> inline T make_sqrt5()    { return from_reference<T>(s_sqrt5); }
template<typename T> inline T make_inv_sqrt2(){ return from_reference<T>(s_inv_sqrt2); }

template<typename T> inline T make_ln2()      { return from_reference<T>(s_ln2); }
template<typename T> inline T make_ln10()     { return from_reference<T>(s_ln10); }
template<typename T> inline T make_log2e()    { return from_reference<T>(s_log2e); }
template<typename T> inline T make_log2_10()  { return from_reference<T>(s_log2_10); }
template<typename T> inline T make_log10e()   { return from_reference<T>(s_log10e); }
template<typename T> inline T make_log10_2()  { return from_reference<T>(s_log10_2); }

template<typename T> inline T make_two_over_sqrt_pi() { return from_reference<T>(s_two_over_sqrt_pi); }
template<typename T> inline T make_euler_gamma()      { return from_reference<T>(s_euler_gamma); }

}} // namespace sw::universal
